import{_ as t,o as a,c as n,ag as o}from"./chunks/framework.CvgP6Fyv.js";const c=JSON.parse('{"title":"PDF-aanpassing","description":"","frontmatter":{},"headers":[],"relativePath":"nl/settings/pdf.md","filePath":"nl/settings/pdf.md"}'),i={name:"nl/settings/pdf.md"};function r(s,e,l,d,u,g){return a(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="pdf-aanpassing" tabindex="-1">PDF-aanpassing <a class="header-anchor" href="#pdf-aanpassing" aria-label="Permalink to &quot;PDF-aanpassing&quot;">​</a></h1><p>Pas het uiterlijk van je factuur-, offerte- en creditnota-PDF&#39;s aan zodat ze passen bij je huisstijl.</p><h2 id="pdf-editor" tabindex="-1">PDF-editor <a class="header-anchor" href="#pdf-editor" aria-label="Permalink to &quot;PDF-editor&quot;">​</a></h2><p>De visuele PDF-editor stelt je in staat om je documentlay-out aan te passen met een live voorbeeld.</p><h3 id="de-editor-openen" tabindex="-1">De editor openen <a class="header-anchor" href="#de-editor-openen" aria-label="Permalink to &quot;De editor openen&quot;">​</a></h3><p>Ga naar <strong>Bedrijf &gt; PDF-editor</strong> of open deze via Bedrijf &gt; Huisstijl.</p><h3 id="aanpassingsopties" tabindex="-1">Aanpassingsopties <a class="header-anchor" href="#aanpassingsopties" aria-label="Permalink to &quot;Aanpassingsopties&quot;">​</a></h3><h4 id="lay-out" tabindex="-1">Lay-out <a class="header-anchor" href="#lay-out" aria-label="Permalink to &quot;Lay-out&quot;">​</a></h4><ul><li><strong>Logopositie en -grootte</strong> — Plaats je logo waar het het beste uitkomt</li><li><strong>Bedrijfsinfo-plaatsing</strong> — Positioneer je bedrijfsgegevens</li><li><strong>Klantinfo-plaatsing</strong> — Waar klantgegevens verschijnen</li><li><strong>Regelitemtabel</strong> — Kolombreedtes en uitlijning</li></ul><h4 id="inhoud" tabindex="-1">Inhoud <a class="header-anchor" href="#inhoud" aria-label="Permalink to &quot;Inhoud&quot;">​</a></h4><p>Kies welke velden je wilt tonen of verbergen:</p><ul><li>BTW-nummer bedrijf</li><li>KVK-nummer</li><li>IBAN / bankgegevens</li><li>Betalingstermijn</li><li>Notitiesectie</li><li>Voettekst</li></ul><h4 id="stijl" tabindex="-1">Stijl <a class="header-anchor" href="#stijl" aria-label="Permalink to &quot;Stijl&quot;">​</a></h4><ul><li><strong>Lettertype</strong> — Kies uit beschikbare lettertypen</li><li><strong>Lettergrootte</strong> — Pas tekstgrootte aan</li><li><strong>Accentkleur</strong> — Je merkkleur voor kopteksten en accenten</li><li><strong>Regelafstand</strong> — Pas de documentdichtheid aan</li></ul><h3 id="voorbeeld" tabindex="-1">Voorbeeld <a class="header-anchor" href="#voorbeeld" aria-label="Permalink to &quot;Voorbeeld&quot;">​</a></h3><p>De editor toont een realtime voorbeeld met voorbeeldgegevens. Je kunt ook een <strong>voorbeeld-PDF</strong> genereren om precies te zien hoe een geprinte factuur eruitziet.</p><h2 id="documenttypen" tabindex="-1">Documenttypen <a class="header-anchor" href="#documenttypen" aria-label="Permalink to &quot;Documenttypen&quot;">​</a></h2><p>PDF-instellingen gelden voor alle gegenereerde documenten:</p><ul><li><strong>Facturen</strong> — Standaard factuurtype</li><li><strong>Offertes</strong> — Offertedocumenten</li><li><strong>Creditnota&#39;s</strong> — Terugbetalings-/correctiedocumenten</li><li><strong>Herinneringen</strong> — Betalingsherinneringsdocumenten</li></ul><h2 id="taalondersteuning" tabindex="-1">Taalondersteuning <a class="header-anchor" href="#taalondersteuning" aria-label="Permalink to &quot;Taalondersteuning&quot;">​</a></h2><p>PDF&#39;s worden gegenereerd in de taal van de factuur. Als je een factuur in het Duits verstuurt, verschijnen de PDF-labels (zoals &quot;Rechnung&quot;, &quot;Falligkeitsdatum&quot;, &quot;Gesamt&quot;) in het Duits.</p><p>Ondersteunde PDF-talen: Engels, Nederlands, Duits, Frans.</p><h2 id="logo-vereisten" tabindex="-1">Logo-vereisten <a class="header-anchor" href="#logo-vereisten" aria-label="Permalink to &quot;Logo-vereisten&quot;">​</a></h2><p>Voor het beste resultaat:</p><ul><li><strong>Formaat:</strong> PNG met transparante achtergrond (aanbevolen), JPG of SVG</li><li><strong>Resolutie:</strong> Minimaal 300px breed</li><li><strong>Beeldverhouding:</strong> Landschap- of vierkante logo&#39;s werken het beste</li><li><strong>Bestandsgrootte:</strong> Onder 2MB</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>SVG-logo&#39;s worden automatisch omgezet naar PNG voor e-mailcompatibiliteit.</p></div><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Genereer een voorbeeld-PDF na wijzigingen om de lay-out te verifieren</li><li>Gebruik de accentkleur van je merk voor een professionele uitstraling</li><li>Houd de lay-out schoon — overlaad de PDF niet met te veel informatie</li><li>Test met een echte factuur (aan jezelf) voordat je naar klanten verstuurt</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Geavanceerde PDF-aanpassing vereist het <strong>Pro</strong>-abonnement of hoger.</p></div>',29)])])}const p=t(i,[["render",r]]);export{c as __pageData,p as default};
